## 3.  C++ stub – `pcapng_stubs.cpp`

> **Important** – compile this file **as C++** (e.g. `ocamlopt -c -ccopt -std=c++17 pcapng_stubs.cpp`) and link the resulting object with the C++ library (`-lpcapng`).  
> The file uses the OCaml runtime API (`caml/mlvalues.h`, …) and the C++ API of `libpcapng`.  Adjust the include paths and the namespace according to the real library you are binding to.

```cpp
/* ----------------------------------------------------------------------
   pcapng_stubs.cpp – C++ bridge for the OCaml libpcapng bindings
   ---------------------------------------------------------------------- */

#define CAML_NAME_SPACE   /* avoid name clashes with C++ std:: */
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/callback.h>
#include <caml/bigarray.h>
#include <caml/threads.h>

#include <memory>
#include <string>
#include <vector>
#include <stdexcept>

/* ----------------------------------------------------------------------
   The real libpcapng API (replace with the real header you have)
   ---------------------------------------------------------------------- */
namespace libpcapng {

/* A tiny fake API – replace with the real one.
   The real library will have a class that can read a file and produce
   frames one by one.  For illustration we only need the shape. */
struct Frame {
    double   ts;          // timestamp (seconds, fractional)
    uint32_t caplen;      // captured length
    uint32_t origlen;     // original length on the wire
    const uint8_t* data;  // pointer to captured bytes (valid until next frame)
};

class Reader {
public:
    explicit Reader(const std::string& filename) {
        // real implementation would open the file and parse the header
        // For illustration we throw an exception if the file does not exist.
        // In real code replace with proper error handling.
        if (filename.empty())
            throw std::runtime_error("empty filename");
        // ... open file, initialise parser ...
    }
    ~Reader() { /* close file, free resources */ }

    /** Return true and fill [out] if a frame is available,
        return false when EOF is reached. */
    bool next(Frame& out) {
        // Replace with real iteration logic.
        // Here we simulate EOF immediately.
        (void)out;
        return false;
    }
};

} // namespace libpcapng
/* ---------------------------------------------------------------------- */

/* ----------------------------------------------------------------------
   OCaml custom block that holds a pointer to the C++ Reader.
   ---------------------------------------------------------------------- */
typedef struct {
    std::unique_ptr<libpcapng::Reader> reader;
} pcapng_handle;

/* finaliser – called when the OCaml value is GC‑collected */
static void pcapng_handle_finalize(value v) {
    pcapng_handle *h = (pcapng_handle *)Data_custom_val(v);
    delete h;                     // unique_ptr destructor closes the file
}

/* custom operations descriptor */
static struct custom_operations pcapng_handle_ops = {
    "org.example.pcapng_handle",
    pcapng_handle_finalize,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

/* Helper: allocate a fresh custom block */
static value alloc_handle(pcapng_handle *h) {
    CAMLparam0();
    CAMLlocal1(v);
    v = caml_alloc_custom(&pcapng_handle_ops,
                          sizeof(pcapng_handle *),
                          0,   /* mem_allocated, not used */
                          1);  /* finaliser will run */
    Store_custom_val(v, h);
    CAMLreturn(v);
}

/* ----------------------------------------------------------------------
   Exceptions
   ---------------------------------------------------------------------- */
static void raise_error(const std::string &msg) {
    caml_raise_with_string(*caml_named_value("Pcapng.Error"), msg.c_str());
}

/* ----------------------------------------------------------------------
   Helper: build an OCaml [frame] record.
   The OCaml type defined in the .mli is:
   { ts : float; caplen : int; origlen : int; data : bytes }
   ---------------------------------------------------------------------- */
static value caml_frame_of_cpp(const libpcapng::Frame &f) {
    CAMLparam0();
    CAMLlocal4(ocaml_rec, ts_val, caplen_val, origlen_val, data_val);

    /* 1. timestamp (float) */
    ts_val = caml_copy_double(f.ts);

    /* 2. caplen & origlen (int) – OCaml ints are 31‑bit on 32‑bit,
       63‑bit on 64‑bit, both are enough for packet lengths. */
    caplen_val  = Val_int(static_cast<int>(f.caplen));
    origlen_val = Val_int(static_cast<int>(f.origlen));

    /* 3. data – copy into a fresh OCaml string (bytes). */
    data_val = caml_alloc_string(f.caplen);
    memcpy(String_val(data_val), f.data, f.caplen);

    /* 4. allocate the record (4 fields, tag 0) */
    ocaml_rec = caml_alloc(4, 0);
    Store_field(ocaml_rec, 0, ts_val);
    Store_field(ocaml_rec, 1, caplen_val);
    Store_field(ocaml_rec, 2, origlen_val);
    Store_field(ocaml_rec, 3, data_val);

    CAMLreturn(ocaml_rec);
}

/* ----------------------------------------------------------------------
   Primitive: open_file : string -> t
   ---------------------------------------------------------------------- */
extern "C" CAMLprim value pcapng_open_file(value v_path) {
    CAMLparam1(v_path);
    CAMLlocal1(v_handle);
    const char *c_path = String_val(v_path);
    try {
        std::unique_ptr<libpcapng::Reader> rdr(
            new libpcapng::Reader(std::string(c_path)));
        pcapng_handle *h = new pcapng_handle();
        h->reader = std::move(rdr);
        v_handle = alloc_handle(h);
    } catch (const std::exception &e) {
        raise_error(e.what());
    }
    CAMLreturn(v_handle);
}

/* ----------------------------------------------------------------------
   Primitive: close : t -> unit
   ---------------------------------------------------------------------- */
extern "C" CAMLprim value pcapng_close(value v_handle) {
    CAMLparam1(v_handle);
    pcapng_handle *h = *(pcapng_handle **)Data_custom_val(v_handle);
    // Explicitly reset the unique_ptr; the Reader destructor runs now.
    h->reader.reset();
    CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   Primitive: iter : (frame -> unit) -> t -> unit
   ---------------------------------------------------------------------- */
extern "C" CAMLprim value pcapng_iter(value v_func, value v_handle) {
    CAMLparam2(v_func, v_handle);
    CAMLlocal1(v_frame);
    pcapng_handle *h = *(pcapng_handle **)Data_custom_val(v_handle);
    libpcapng::Reader &reader = *(h->reader);

    /* The iterator may be called from any thread (e.g. the user may
       run [Thread.create] and then call [iter]), therefore we protect
       the OCaml runtime with the standard macros. */
    caml_release_runtime_system();

    try {
        libpcapng::Frame cpp_frame;
        while (reader.next(cpp_frame)) {
            /* Build an OCaml record for the current frame */
            v_frame = caml_frame_of_cpp(cpp_frame);

            /* Call the user supplied OCaml function.
               Use caml_callback_exn to catch exceptions. */
            value result = caml_callback_exn(v_func, v_frame);
            if (Is_exception_result(result)) {
                /* Propagate the exception to the caller of iter */
                caml_acquire_runtime_system();
                caml_raise(result);
                /* unreachable */
            }
        }
    } catch (const std::exception &e) {
        caml_acquire_runtime_system();
        raise_error(e.what());
        /* unreachable */
    }

    caml_acquire_runtime_system();
    CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   Primitive: fold : ('a -> frame -> 'a) -> 'a -> t -> 'a
   ---------------------------------------------------------------------- */
extern "C" CAMLprim value pcapng_fold(value v_f, value v_acc, value v_handle) {
    CAMLparam3(v_f, v_acc, v_handle);
    CAMLlocal2(v_frame, v_new_acc);
    pcapng_handle *h = *(pcapng_handle **)Data_custom_val(v_handle);
    libpcapng::Reader &reader = *(h->reader);

    caml_release_runtime_system();

    try {
        libpcapng::Frame cpp_frame;
        while (reader.next(cpp_frame)) {
            v_frame = caml_frame_of_cpp(cpp_frame);
            v_new_acc = caml_callback_exn(v_f, v_acc, v_frame);
            if (Is_exception_result(v_new_acc)) {
                caml_acquire_runtime_system();
                caml_raise(v_new_acc);
            }
            v_acc = v_new_acc;   // continue folding with the new accumulator
        }
    } catch (const std::exception &e) {
        caml_acquire_runtime_system();
        raise_error(e.what());
    }

    caml_acquire_runtime_system();
    CAMLreturn(v_acc);
}

/* ----------------------------------------------------------------------
   Primitive: to_list : t -> frame list
   ---------------------------------------------------------------------- */
extern "C" CAMLprim value pcapng_to_list(value v_handle) {
    CAMLparam1(v_handle);
    CAMLlocal3(v_cons, v_frame, v_result);
    pcapng_handle *h = *(pcapng_handle **)Data_custom_val(v_handle);
    libpcapng::Reader &reader = *(h->reader);

    v_result = Val_int(0);        // the empty list []

    caml_release_runtime_system();

    try {
        libpcapng::Frame cpp_frame;
        while (reader.next(cpp_frame)) {
            v_frame = caml_frame_of_cpp(cpp_frame);
            v_cons = caml_alloc(2, 0);          // :: constructor
            Store_field(v_cons, 0, v_frame);
            Store_field(v_cons, 1, v_result);
            v_result = v_cons;
        }
    } catch (const std::exception &e) {
        caml_acquire_runtime_system();
        raise_error(e.what());
    }

    caml_acquire_runtime_system();
    CAMLreturn(v_result);
}

/* ----------------------------------------------------------------------
   Register the custom exception name at load time.
   ---------------------------------------------------------------------- */
static struct caml_named_value *error_exn = NULL;

extern "C" CAMLprim value caml_pcapng_init(value unit) {
    CAMLparam1(unit);
    /* Create a unique exception value that we can raise from C++.
       The name must match the one used in pcapng.mli (Error). */
    error_exn = caml_named_value("Pcapng.Error");
    if (error_exn == NULL) {
        caml_register_named_value("Pcapng.Error", caml_alloc_small(0, 0));
    }
    CAMLreturn(Val_unit);
}
```

### 3.1 Explanation of the stub

| Part | What it does |
|------|--------------|
| **`pcapng_handle`** | Holds a `std::unique_ptr<Reader>`; the OCaml value is a custom block that owns this pointer. |
| **`alloc_handle` / finaliser** | Allocate the custom block and make sure the C++ object is destroyed when the OCaml value is GC‑collected. |
| **`raise_error`** | Turns a C++ `std::exception` into the OCaml exception `Pcapng.Error`. |
| **`caml_frame_of_cpp`** | Copies the C++ `Frame` into an OCaml record (`float * int * int * bytes`). No pointer is kept – the data is duplicated into a fresh OCaml string (which is a `bytes`). |
| **`pcapng_iter`** | The core of the “per‑row” API.  It releases the OCaml runtime lock (`caml_release_runtime_system`) before entering the C++ loop, builds a record for each frame, and calls the user‑supplied OCaml function via `caml_callback_exn`.  If the OCaml callback raises, the exception is re‑raised to the caller of `iter`. |
| **`pcapng_fold`** | Same pattern as `iter`, but returns an accumulator. |
| **`pcapng_to_list`** | Convenience wrapper that builds a list of all frames (useful for quick tests). |
| **`caml_pcapng_init`** | Registers the named exception `Pcapng.Error`.  This function is automatically called by OCaml when the library is loaded (via `Dl.dlopen` or the normal linking). |

### 3.2 Thread‑safety

* The iterator runs **outside** the OCaml runtime – we call `caml_release_runtime_system` before the C++ loop and reacquire it afterwards.  This means that while a long `iter` is running, other OCaml threads can continue to execute.
* The callback itself runs **inside** the OCaml runtime, so it may allocate, raise, etc.  If the callback raises, we stop the iteration and propagate the exception.

### 3.3 Memory management

* Every frame is copied into a fresh OCaml `bytes`.  The C++ library owns its memory; the copy ensures that the OCaml value is independent of the C++ iterator’s internal buffers.
* The `pcapng_handle` custom block owns the `Reader` via a `unique_ptr`; the finaliser guarantees that the file descriptor is closed even if the user forgets to call `close`.

---

## 4.  How to build the binding

Assuming the sources are in a directory `src/`:

```sh
# 1. Compile the C++ stub (adjust -I to point to the libpcapng headers)
ocamlopt -c -ccopt "-std=c++17 -I/path/to/libpcapng/include" src/pcapng_stubs.cpp

# 2. Compile the OCaml files
ocamlopt -c src/pcapng.mli
ocamlopt -c src/pcapng.ml

# 3. Archive into a library (or link directly)
ocamlopt -a -o libpcapng.cmxa src/pcapng.cmx src/pcapng_stubs.o -cclib -lpcapng

# 4. Use from another OCaml project:
#    ocamlopt -I src -c my_program.ml
#    ocamlopt -o my_program my_program.cmx libpcapng.cmxa
```

If you prefer a single `.cma` (bytecode) library, replace `ocamlopt` with `ocamlc` and add the `-custom` flag to force static linking of the C++ object.

---

## 5.  Example usage (OCaml)

```ocaml
(* test_pcapng.ml *)
let () =
  let handle = Pcapng.open_file "sample.pcapng" in
  (* 1. Simple iteration – print timestamps *)
  Pcapng.iter (fun f ->
    Printf.printf "ts = %.6f  caplen = %d\n%!" f.Pcapng.ts f.Pcapng.caplen
  ) handle;

  (* 2. Fold – count packets larger than 1000 bytes *)
  let big_cnt = Pcapng.fold (fun acc f ->
      if f.Pcapng.caplen > 1000 then acc + 1 else acc
    ) 0 handle in
  Printf.printf "Packets > 1000 bytes: %d\n%!" big_cnt;

  (* 3. Collect everything into a list (only for tiny files) *)
  let frames = Pcapng.to_list handle in
  Printf.printf "Total frames: %d\n%!" (List.length frames);

  Pcapng.close handle
```

Compile and run:

```sh
ocamlopt -o test_pcapng unix.cmxa libpcapng.cmxa test_pcapng.ml
./test_pcapng
```

---

## 6.  Summary of the design

* **Pure OCaml interface** – a single abstract type `t` and a lightweight `frame` record.
* **Per‑frame callback** (`iter`) that mirrors the “apply a function to each row” model used by pandas/Polars.
* **Zero‑copy for the iterator** – the heavy iteration stays in C++; only when a frame reaches the OCaml callback do we allocate a small OCaml record.
* **Exception safety** – C++ exceptions become `Pcapng.Error`, OCaml exceptions raised inside the callback abort the iteration and propagate.
* **Thread‑aware** – the runtime lock is released while walking the C++ iterator, so the binding works nicely in a multithreaded OCaml program.
* **Automatic resource management** – a custom block with a finaliser guarantees that the underlying file is closed even if the user forgets to call `close`.

Feel free to replace the dummy `libpcapng::Reader` implementation with the real one; the rest of the stub stays unchanged. Happy hacking!
